import 'package:flutter/material.dart'; import 'package:injectable/injectable.dart'; import '../utils/app_logger.dart'; @singleton class AppLifecycleService with WidgetsBindingObserver { bool _inForeground = true; bool get inForeground => _inForeground; void initialize() { WidgetsBinding.instance.addObserver(this); AppLogger.info('AppLifecycleService initialized'); } @override void didChangeAppLifecycleState(AppLifecycleState state) { _inForeground = state == AppLifecycleState.resumed; AppLogger.debug('App lifecycle: $state'); } void dispose() => WidgetsBinding.instance.removeObserver(this); }